    def solve(self, s: str) -> bool:
        i = len(s) - 1
        while i >= 0:
            if s[i] == '1':
                j = i
                while j >= 0:
                    if s[j] == '0':
                        return True
                    j -= 1
                i -= 1
            i -= 1
        return False

